// Re-run secrets registry verify via internal webhook.
const n8nBase = (process.env.N8N_BASE_URL || process.env.N8N_URL || 'https://hansvanleeuwen.app.n8n.cloud').replace(/\/$/, '');
const token = process.env.COMMANDER_WEBHOOK_TOKEN || '';

try {
  const resp = await fetch(`${n8nBase}/webhook/secrets-registry-verify`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-COMMANDER-TOKEN': token
    },
    body: JSON.stringify({})
  });
  const report = await resp.json();
  return [{ json: { verify_status: resp.status, report } }];
} catch (e) {
  return [{ json: { verify_status: 0, error: e.message, report: null } }];
}

// All secrets present — run smoke tests.
const n8nBase = (process.env.N8N_BASE_URL || process.env.N8N_URL || 'https://hansvanleeuwen.app.n8n.cloud').replace(/\/$/, '');
const smokeTests = [];

// Test 1: n8n health
try {
  const r = await fetch(`${n8nBase}/healthz`);
  smokeTests.push({ test: 'n8n healthz', status: r.status, ok: r.ok });
} catch (e) {
  smokeTests.push({ test: 'n8n healthz', status: 0, ok: false, error: e.message });
}

// Test 2: n8n API credentials list
try {
  const apiKey = process.env.N8N_API_KEY;
  if (apiKey) {
    const r = await fetch(`${n8nBase}/api/v1/credentials`, {
      headers: { 'X-N8N-API-KEY': apiKey, 'Accept': 'application/json' }
    });
    const data = await r.json();
    smokeTests.push({ test: 'n8n credentials API', status: r.status, ok: r.ok, count: (data.data || []).length });
  }
} catch (e) {
  smokeTests.push({ test: 'n8n credentials API', status: 0, ok: false, error: e.message });
}

const allPassed = smokeTests.every(t => t.ok);
// Optionally activate target workflows (e.g. via n8n API when ACTIVATE_WORKFLOWS env is set)
const activated_workflows = [];
return [{ json: {
  reconciled: true,
  ok: allPassed,
  timestamp: new Date().toISOString(),
  smoke_tests: smokeTests,
  activated_workflows,
  report: $input.first().json.report
} }];

// Still missing secrets — escalate.
const input = $input.first().json;
const report = input.report || {};
return [{ json: {
  reconciled: false,
  ok: false,
  timestamp: new Date().toISOString(),
  escalation: 'Secrets still missing after provisioning. Manual intervention required.',
  missing: report.all_missing || report.missing || [],
  warnings: report.warnings || [],
  action: 'Review docs/runbooks/missing-secrets.md and re-run: commander secrets:heal'
} }];
